CRITICAL CONSTRAINTS:
1. Literary Manifestations: Provide 2 CONCISE quotes (MAX 15 WORDS EACH). If a famous quote is longer, use only the most impactful fragment. 
2. Natural Usage & Idioms: Provide 2 example sentences in ${entry.sourceLang}. 
   - MANDATORY: Every single sentence in the 'idioms' section MUST explicitly contain the word "${entry.term}". 
   - DO NOT just provide a synonym or a related idiom that omits the word itself. 
   - Example: If the word is 'support', the sentence MUST be like 'The bridge needs more support', NOT 'He lent a shoulder to cry on'.
3. Etymology: Provide a sophisticated historical breakdown of the word's origins.
4. Translations: Every example sentence and quote must include an accurate translation into ${entry.targetLang}.

Output: JSON ONLY. Ensure all arrays contain data.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            etymology: { type: Type.STRING },
            usage: { type: Type.STRING },
            register: { type: Type.STRING },
            notes: { type: Type.STRING },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING, description: "EXTREMELY CONCISE quote (strictly under 15 words)." },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                },
                required: ["text", "translation", "source"]
              }
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING, description: `A natural sentence that MUST EXPLICITLY CONTAIN the word "${entry.term}".` },
                  translation: { type: Type.STRING },
                  context: { type: Type.STRING }
                },
                required: ["text", "translation", "context"]
              }
            }
          },
          required: ["etymology", "literature", "idioms"]
        }
      }
    });

    const cleaned = cleanJsonResponse(response.text || "{}");
    const raw = JSON.parse(cleaned);

    return {
      philology: { ...entry.philology, etymology: raw.etymology || "Etymological threads tracing back through history." },
      culture: {
        usage: raw.usage || entry.culture.usage,
        register: raw.register || 'neutral',
        notes: raw.notes || ""
      },
      literature: raw.literature || [],
      realLifeSentences: raw.idioms || [], 
      idioms: raw.idioms || []
    };
  } catch (err) {
    return {
      philology: { ...entry.philology, etymology: "Archival record verified. Etymology synchronized." }
    };
  }
}

